// Extract file from webhook payload
const file = items[0].binary.file;
const fileName = items[0].json.fileName || 'document.pdf';
const fileSize = items[0].json.fileSize;

return [
  {
    json: {
      fileName,
      fileSize,
      status: 'received',
      timestamp: new Date().toISOString()
    },
    binary: {
      file: file
    }
  }
];

// Use pdf-parse library to extract text from PDF
const PDFParser = require('pdf-parse');
const fs = require('fs');

let pdfData = await PDFParser(items[0].binary.file.data);

return [
  {
    json: {
      fileName: items[0].json.fileName,
      totalPages: pdfData.numpages,
      text: pdfData.text,
      metadata: pdfData.info
    }
  }
];

// Chunk PDF text into overlapping chunks
const text = items[0].json.text;
const chunkSize = 1000;
const overlapSize = 200;
const chunks = [];

for (let i = 0; i < text.length; i += chunkSize - overlapSize) {
  const chunk = text.substring(i, i + chunkSize);
  if (chunk.trim().length > 0) {
    chunks.push({
      text: chunk,
      startIndex: i,
      pageNumber: Math.floor(i / (text.length / items[0].json.totalPages)) + 1
    });
  }
}

return [
  {
    json: {
      fileName: items[0].json.fileName,
      totalPages: items[0].json.totalPages,
      chunks: chunks,
      chunkCount: chunks.length
    }
  }
];

// Loop through chunks and create embedding requests
const chunks = items[0].json.chunks;
const embeddings = [];

for (const chunk of chunks) {
  embeddings.push({
    chunk_id: Math.random().toString(36).substr(2, 9),
    text: chunk.text,
    page_number: chunk.pageNumber,
    start_index: chunk.startIndex
  });
}

return [
  {
    json: {
      fileName: items[0].json.fileName,
      embeddings: embeddings,
      embeddingCount: embeddings.length
    }
  }
];

// Error handler - log and send error response
const error = items[0].json.error || 'Unknown error';

console.error('Workflow error:', error);

return [
  {
    json: {
      status: 'error',
      message: error.toString(),
      timestamp: new Date().toISOString()
    }
  }
];
